using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. Type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<Person>(out var resolved))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded – type: {resolved!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

// 2b. Type that is NOT resolvable (empty resolver → no metadata available)
var empty = new JsonSerializerOptions { TypeInfoResolver = new EmptyResolver() };

if (empty.TryGetTypeInfo<Person>(out var notResolved))
    Console.WriteLine($"TryGetTypeInfo<Person> on empty resolver succeeded – unexpected");
else
    Console.WriteLine("TryGetTypeInfo<Person> on empty resolver returned false (expected)");

// --- Types ---

public record Person(string Name, int Age);

/// <summary>A resolver that deliberately resolves nothing.</summary>
file class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

